-- Острый Толбачик (3 682 м) — потухший брат-близнец
UPDATE agent_route_knowledge SET updated_at = NOW(), is_visible = TRUE, activity_type = 'trekking', description =
'Вулкан Острый Толбачик — 3 682 м (55.831°N, 160.326°E), потухший стратовулкан к северо-западу от Плоского. Образует вместе с Плоским Толбачиком двуглавый массив Толбачик. Острый конус с эродированным кратером — классический пример древнего потухшего вулкана. Восхождение сложнее, чем на Плоский: снежные гребни, скальные участки. Часть маршрутов вокруг вулканов Толбачика. С вершины в ясную погоду виден Ключевской и весь Ключевской кластер. Посещается в связке с Плоским Толбачиком.'
