-- Северный прорыв БТТИ 1975 — лунный пейзаж
UPDATE agent_route_knowledge SET updated_at = NOW(), is_visible = TRUE, activity_type = 'eco', description =
'Северный прорыв — главный шлаковый конус БТТИ (Большого Толбачинского трещинного извержения) 1975–1976 гг. (55.689°N, 160.245°E). Высота конуса ~300 м, диаметр кратера ~700 м. Вокруг — бескрайние чёрные шлаковые поля с застывшими лавовыми потоками, лавовыми трубками, лопнувшими пузырями лавы. Пейзаж напоминает поверхность Луны или Марса — сюда приезжали советские космонавты для тренировок. Пешеходный маршрут от базового лагеря 4 км (3–4 ч). Вершина конуса доступна для подъёма. Рядом — прорывы им. Набоко и Меняйлова.'
WHERE id = '84a281c7-c690-4732-82e5-335c6d90c04d';

-- Кратер Марс — красный шлаковый конус
UPDATE agent_route_knowledge SET updated_at = NOW(), is_visible = TRUE, activity_type = 'eco', description =
