-- Кратер Юпитер
UPDATE agent_route_knowledge SET updated_at = NOW(), is_visible = TRUE, activity_type = 'eco', description =
'Кратер Юпитер — шлаковый конус на лавовых полях Толбачика (55.900°N, 160.512°E). Соседствует с кратером Марс. Тёмный, почти чёрный шлак с юпитерианским рисунком застывших лавовых потоков. Часть системы побочных конусов, возникших в ходе БТТИ 1975–1976 гг. Посещается в один маршрут с кратером Марс и Северным прорывом — классический «Толбачинский треугольник». Кратер открыт для подъёма: виды на весь вулканический массив.'
