-- Карымский (1 486 м) — самый активный вулкан Камчатки
UPDATE agent_route_knowledge SET updated_at = NOW(), is_visible = TRUE, activity_type = 'helicopter', description =
'Карымский вулкан — 1 486 м (54.048°N, 159.443°E), наиболее активный вулкан Камчатки. Извергается практически непрерывно с 1996 года. Регулярные пепловые выбросы 1–3 км в высоту несколько раз в сутки. В 1996 году синхронно с Карымским произошло подводное извержение в Карымском озере — уникальный случай одновременных извержений вулкана и вулкана под озером. Вход в Кроноцкий заповедник. Посещение только вертолётом (пешком — несколько дней через безлюдную тундру). Вулкан строго охраняется. Живая лаборатория вулканологии.'
