-- ══════════════════════════════════════════════════════════════
-- ОБНОВИТЬ search_text ДЛЯ ВСЕХ ИЗМЕНЁННЫХ ЗАПИСЕЙ
-- ══════════════════════════════════════════════════════════════
UPDATE agent_route_knowledge
SET search_text = TRIM(title || ' ' || COALESCE(description,'') || ' ' || COALESCE(location_type,'') || ' ' || COALESCE(activity_type,''))
WHERE is_visible = TRUE AND updated_at > NOW() - INTERVAL '5 minutes';
